{
  "governance_model": {
    "name": "Three-Tier ICAAP Governance",
    "tiers": [
      {
        "tier": 1,
        "body": "Board of Directors",
        "role": "Strategic Oversight & Final Approval",
        "meeting_frequency": "Annual (ICAAP approval) / Quarterly (monitoring)",
        "key_responsibilities": [
          "Approve ICAAP policy framework",
          "Approve risk appetite statement",
          "Approve ICAAP report and capital plan",
          "Ensure adequate resources for ICAAP"
        ]
      },
      {
        "tier": 2,
        "body": "Board Risk Committee / ALCO",
        "role": "Management Oversight & Review",
        "meeting_frequency": "Quarterly (minimum)",
        "key_responsibilities": [
          "Review ICAAP methodology and assumptions",
          "Review stress testing scenarios and results",
          "Recommend ICAAP report to BoD",
          "Monitor risk profile against appetite"
        ]
      },
      {
        "tier": 3,
        "body": "Capital Working Group",
        "role": "Technical Execution & Analysis",
        "meeting_frequency": "Monthly / Weekly during ICAAP preparation",
        "key_responsibilities": [
          "Prepare ICAAP data and documentation",
          "Conduct stress testing and analysis",
          "Draft ICAAP report",
          "Track action items"
        ]
      }
    ],
    "sign_off_flow": [
      {"step": 1, "action": "CWG prepares ICAAP draft", "owner": "Head of Risk Analytics"},
      {"step": 2, "action": "Heads of Risk/Finance review", "owner": "CRO / CFO"},
      {"step": 3, "action": "ALCO / ICAAP Mgmt Committee review", "owner": "ALCO Chair"},
      {"step": 4, "action": "Board Risk Committee review and recommendation", "owner": "BRC Chair"},
      {"step": 5, "action": "Board of Directors final approval", "owner": "BoD"},
      {"step": 6, "action": "Regulatory submission", "owner": "CRO / CFO"}
    ],
    "escalation_levels": [
      {
        "level": 1,
        "name": "Operational",
        "actors": "Risk Analyst → Head of Risk Analytics",
        "timeframe": "Within 24 hours"
      },
      {
        "level": 2,
        "name": "Management",
        "actors": "CRO/CFO → ALCO",
        "timeframe": "Within 48 hours"
      },
      {
        "level": 3,
        "name": "Board",
        "actors": "Board Risk Committee → Board of Directors",
        "timeframe": "Within 1 week"
      },
      {
        "level": 4,
        "name": "Regulatory",
        "actors": "BoD → Regulator",
        "timeframe": "Immediate for capital breach"
      }
    ]
  },
  "metadata": {
    "document_version": "1.0",
    "regulatory_alignment": ["EBA ICAAP Guidelines", "Basel Committee CP 31", "Federal Reserve SR 09-1"],
    "applicable_jurisdictions": ["General - multi-jurisdictional"],
    "review_cycle": "Annual + trigger-based"
  }
}

{
  "portfolio_context": {
    "total_obligors": 10000,
