      {"segment": "SME - Low Risk", "obligors": 2000, "predicted": 22, "actual": 19, "deviation_pct": 15.8, "status": "MONITOR"},
      {"segment": "SME - High Risk", "obligors": 1000, "predicted": 58, "actual": 63, "deviation_pct": -7.9, "status": "PASS"},
      {"segment": "CRE", "obligors": 1200, "predicted": 36, "actual": 33, "deviation_pct": 9.1, "status": "PASS"},
      {"segment": "Corporate", "obligors": 800, "predicted": 16, "actual": 18, "deviation_pct": -11.1, "status": "MONITOR"}
