      "stage_1": {"model": 12400000, "inventory": 11800000, "delta": 600000, "delta_pct": 5.1},
      "stage_2": {"model": 8700000, "inventory": 9200000, "delta": -500000, "delta_pct": -5.4},
      "stage_3": {"model": 15300000, "inventory": 14900000, "delta": 400000, "delta_pct": 2.7},
      "total": {"model": 36400000, "inventory": 35900000, "delta": 500000, "delta_pct": 1.4}
