  },
  "management_overlays": {
    "overlays": [
      {
        "id": "OV-001",
        "description": "Post-COVID uncertainty uplift",
        "magnitude": "+15 bps PD (all segments)",
        "rationale": "Top-down macro uncertainty",
        "statistical_support": "WEAK",
        "empirical_evidence": "Recent default rate 1.7% vs model 1.8%",
        "consistent": false,
        "finding": "Potentially excessive - broad uplift not segmented, post-overlay PD exceeds actual experience"
      },
      {
        "id": "OV-002",
        "description": "Retail concentration risk",
        "magnitude": "+5% LGD (retail only)",
        "rationale": "Regional concentration in high-unemployment areas",
        "statistical_support": "MODERATE",
        "empirical_evidence": "Regional LGDs 34-37% vs model 32%",
        "consistent": true,
        "finding": "Justified - aligns with observed regional data"
      },
      {
        "id": "OV-003",
        "description": "Climate risk - transition",
        "magnitude": "+10% PD (energy sector)",
        "rationale": "Regulatory transition risk",
        "statistical_support": "STRONG",
        "empirical_evidence": "Energy sector PD 2.4% vs model 2.1%",
        "consistent": true,
        "finding": "Justified - aligns with stress expectations"
      }
    ],
    "net_overlay_impact": {
      "pre_overlay_ecl": 36400000,
      "overlay_adjustment": 3200000,
      "post_overlay_ecl": 39600000,
      "inventory_ecl": 35900000,
      "post_vs_inventory_pct": 10.3,
      "assessment": "Prudent but potentially over-conservative"
    }
  },
  "sensitivity_heatmap": {
    "description": "Relative ECL change per unit shock, normalized 0-1",
    "matrix": {
      "Retail-Prime": {"GDP": 0.25, "Unemployment": 0.18, "Interest_Rate": 0.08, "Credit_Score": 0.45, "LTV": 0.38},
      "Retail-Subprime": {"GDP": 0.52, "Unemployment": 0.48, "Interest_Rate": 0.12, "Credit_Score": 0.62, "LTV": 0.55},
      "SME-Low": {"GDP": 0.35, "Unemployment": 0.22, "Interest_Rate": 0.15, "Credit_Score": 0.28, "LTV": 0.42},
      "SME-High": {"GDP": 0.58, "Unemployment": 0.52, "Interest_Rate": 0.20, "Credit_Score": 0.35, "LTV": 0.50},
      "CRE": {"GDP": 0.65, "Unemployment": 0.38, "Interest_Rate": 0.45, "Credit_Score": 0.18, "LTV": 0.72},
      "Corporate": {"GDP": 0.48, "Unemployment": 0.30, "Interest_Rate": 0.28, "Credit_Score": 0.22, "LTV": 0.35}
    }
  },
  "recommendations": [
    {"id": "REC-001", "finding": "Model calibration within tolerance (H-L p=0.14)", "severity": "LOW", "action": "Continue monitoring quarterly"},
    {"id": "REC-002", "finding": "SME-Low and Corporate segments show >10% deviation", "severity": "MEDIUM", "action": "Drill down into segment-specific scorecards"},
    {"id": "REC-003", "finding": "OV-001 (broad PD uplift) appears excessive", "severity": "HIGH", "action": "Replace with segment-specific overlay or reduce magnitude"},
    {"id": "REC-004", "finding": "CRE most sensitive to GDP & LTV shocks", "severity": "MEDIUM", "action": "Enhance stress testing for CRE portfolio"},
    {"id": "REC-005", "finding": "Post-overlay ECL 10.3% above actual experience", "severity": "HIGH", "action": "Review overlay governance; challenge conservatism"}
  ]
}
